devHandoff.css:
.check path{stroke-dasharray:var(--len);stroke-dashoffset:var(--len);transition:stroke-dashoffset var(--motion-duration-moderate) var(--motion-ease-smooth)}
input:checked+.box .check path{stroke-dashoffset:0}
.box{transition:background-color var(--motion-duration-base) var(--motion-ease-smooth)}
